MRFBackProfileCmd::MRFBackProfileCmd() :
CATStateCommand ("MRFBackProfileCmd", CATDlgEngOneShot, CATCommandModeExclusive)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pMRFBackProfileDlg(NULL)
, _pPathElementAgentForSurface(NULL)
, _pPathElementAgentForVentGeomSet(NULL)
, _pDialogAgentForSourceSurface(NULL)
, _pDialogAgentForVentGeomSet(NULL)
, _pPathElementForSourceSurface(NULL)
, _pPathElementForVentGeomSet(NULL)
, _pHSO(NULL)
, _pEditor(NULL)
, _spSourceSurface(NULL_var)
, _spVentGeomSet(NULL_var)
, _spInstantiatedBackProfilePart(NULL_var)
, _spActiveInstBackProfProduct(NULL_var)
, _spRootProduct(NULL)
, _pPathElementOnTargetGeomSet(NULL)
, _spOnBackProfileGeomSet(NULL_var)
, _pApplicationFrame(NULL)
{

	_pApplicationFrame = CATApplicationFrame::GetFrame();

	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
	}

	pOnMRFBackProfileOperations = new MRFBackProfileOperations();
	_spOnListOf2DVent.RemoveAll();
	_spOnListOf3DVent.RemoveAll();
	_spOnListOfIntersectionPoint.RemoveAll();

	_spRootProduct = MRFProdStrServices::GetRootPLMProduct();
	//_spRootProduct->AddRef();

	_isSourceSurfaceSelected = false;
	_isPreviewClicked = false;
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFBackProfileCmd::~MRFBackProfileCmd()
{
	if (_pMRFBackProfileDlg)
		_pMRFBackProfileDlg->RequestDelayedDestruction();  _pMRFBackProfileDlg = NULL;

	if (_pPathElementAgentForSurface)
		_pPathElementAgentForSurface->RequestDelayedDestruction(); _pPathElementAgentForSurface = NULL;

	if (_pPathElementAgentForVentGeomSet)
		_pPathElementAgentForVentGeomSet->RequestDelayedDestruction(); _pPathElementAgentForVentGeomSet = NULL;

	if (_pDialogAgentForSourceSurface)
		_pDialogAgentForSourceSurface->RequestDelayedDestruction(); _pDialogAgentForSourceSurface = NULL;

	if (_pDialogAgentForVentGeomSet)
		_pDialogAgentForVentGeomSet->RequestDelayedDestruction(); _pDialogAgentForVentGeomSet = NULL;

	if (_pPathElementForSourceSurface)
		_pPathElementForSourceSurface = NULL;

	if (_pPathElementForVentGeomSet)
		_pPathElementForVentGeomSet = NULL;

	if (NULL != _pHSO && !_pHSO->IsNull())
	{
		_pHSO->Empty();
		_pHSO = NULL;
	}

	if (_pEditor != NULL)
		_pEditor = NULL;

	if (_spSourceSurface)
		_spSourceSurface->Release(); _spSourceSurface = NULL_var;

	if (_spVentGeomSet)
		_spVentGeomSet->Release(); _spVentGeomSet = NULL_var;

	if (_spInstantiatedBackProfilePart)
		_spInstantiatedBackProfilePart->Release(); _spInstantiatedBackProfilePart = NULL_var;

	if (_spActiveInstBackProfProduct)
		_spActiveInstBackProfProduct->Release(); _spActiveInstBackProfProduct = NULL_var;

	_spOnListOf2DVent.RemoveAll();
	_spOnListOf3DVent.RemoveAll();
	_spOnListOfIntersectionPoint.RemoveAll();

	if (_spRootProduct)
		_spRootProduct->Release();  _spRootProduct = NULL;

	if (_pPathElementOnTargetGeomSet)
		_pPathElementOnTargetGeomSet->Release();  _pPathElementOnTargetGeomSet = NULL;

	if (!!_spOnBackProfileGeomSet)
		 _spOnBackProfileGeomSet = NULL_var;

	if (!!_pApplicationFrame)
		_pApplicationFrame = NULL;

	if (!!pOnMRFBackProfileOperations)
		pOnMRFBackProfileOperations->Release(); pOnMRFBackProfileOperations = NULL;

	
}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFBackProfileCmd::BuildGraph()
{


// TODO: Define the StateChart
// ---------------------------

	_pMRFBackProfileDlg = new MRFBackProfileDlg();
	_pMRFBackProfileDlg->Build();
	_pMRFBackProfileDlg->SetVisibility(CATDlgShow);

	if (_pMRFBackProfileDlg)
	{
		CATDlgCombo* pOnComboBackProfile = _pMRFBackProfileDlg->GetComboBoxBackProfile();
		if(pOnComboBackProfile)
			ReadProfileCountFromNLSFile(pOnComboBackProfile);

		AddAnalyseNotificationCB(pOnComboBackProfile, pOnComboBackProfile->GetComboSelectNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnComboBoxModified, NULL);
	}

	_pPathElementAgentForSurface = new CATPathElementAgent("RefSurfacePathElementAgent");
	if (_pPathElementAgentForSurface)
	{
		CATListOfCATString ListSurfaces = GetSurfaceSelectorTypes();

		_pPathElementAgentForSurface->SetOrderedTypeList(ListSurfaces);
		_pPathElementAgentForSurface->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}

	_pPathElementAgentForVentGeomSet = new CATPathElementAgent("VentGeomSetSelectionPathElemAgent");
	if (_pPathElementAgentForVentGeomSet)
	{
		CATListOfCATString ListSurfaces;
		ListSurfaces.Append("CATIBodyRequest");

		_pPathElementAgentForVentGeomSet->SetOrderedTypeList(ListSurfaces);
		_pPathElementAgentForVentGeomSet->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}



	AddAnalyseNotificationCB(_pMRFBackProfileDlg, _pMRFBackProfileDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnOK, NULL);
	AddAnalyseNotificationCB(_pMRFBackProfileDlg, _pMRFBackProfileDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFBackProfileDlg, _pMRFBackProfileDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFBackProfileDlg, _pMRFBackProfileDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnOK, "FromPreviewButton");


	CATDlgContextualMenu* contextMenuClearSelectionSourceSurf = _pMRFBackProfileDlg->GetCustomContextualMenuOfSelectorListSourceSurface();
	if (contextMenuClearSelectionSourceSurf)
		AddAnalyseNotificationCB(contextMenuClearSelectionSourceSurf, contextMenuClearSelectionSourceSurf->GetVisibilityNotification(), (CATCommandMethod)&MRFBackProfileCmd::OnContextMenuSelected, "FromSourceSurfaceSelectorList");

	CATDlgContextualMenu* contextMenuClearSelectionVentGeomSet = _pMRFBackProfileDlg->GetCustomContextualMenuOfSelectorListVentGeomSet();
	if (contextMenuClearSelectionVentGeomSet)
		AddAnalyseNotificationCB(contextMenuClearSelectionVentGeomSet, contextMenuClearSelectionVentGeomSet->GetVisibilityNotification(), (CATCommandMethod)&MRFBackProfileCmd::OnContextMenuSelected, "FromVentSetSelectorList");


	//Dialog States 
	CATDlgSelectorList* pSelectorListSourceSurf = _pMRFBackProfileDlg->GetSelectorListSourceSurf();
	_pDialogAgentForSourceSurface = new CATDialogAgent("SourceSurfaceDialogAgent");
	if (_pDialogAgentForSourceSurface)
	{
		if (NULL != pSelectorListSourceSurf)
		{
			_pDialogAgentForSourceSurface->AcceptOnNotify(pSelectorListSourceSurf, pSelectorListSourceSurf->GetListSelectNotification());
			
		}
	}

	CATDlgSelectorList* pSelectorListVentGeomSet = _pMRFBackProfileDlg->GetSelectorListVentGeomSet();
	_pDialogAgentForVentGeomSet = new CATDialogAgent("VentGeomSetDialogAgent");
	if (_pDialogAgentForVentGeomSet)
	{
		if (NULL != pSelectorListVentGeomSet)
		{
			_pDialogAgentForVentGeomSet->AcceptOnNotify(pSelectorListVentGeomSet, pSelectorListVentGeomSet->GetListSelectNotification());
		}
	}

	CATDlgPushButton* pPushButtonInstantiate = _pMRFBackProfileDlg->GetPushButtonInstantiate();
	if (pPushButtonInstantiate)
	{
		AddAnalyseNotificationCB(pPushButtonInstantiate, pPushButtonInstantiate->GetPushBActivateNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnPushButtonInstantiateClicked, NULL);
	}

	
	CATDlgMultiList* pMultiListOnParm = _pMRFBackProfileDlg->GetMultiListParm();

	if (pMultiListOnParm)
	{
		AddAnalyseNotificationCB(pMultiListOnParm, pMultiListOnParm->GetListCellModifyNotification(), (CATCommandMethod)&MRFBackProfileCmd::OnMultiListParmEdited, NULL);
	}

	//---------------------Adding agents to States STARTS----------------------------------//
	CATDialogState *initialState = GetInitialState("InitialState");
	initialState->AddDialogAgent(_pPathElementAgentForSurface);
	initialState->AddDialogAgent(_pDialogAgentForSourceSurface);
	initialState->AddDialogAgent(_pDialogAgentForVentGeomSet);

	CATDialogState *VentGeomSetSelectionState = AddDialogState("VentGeomSetSelectionState");
	VentGeomSetSelectionState->AddDialogAgent(_pPathElementAgentForVentGeomSet);
	VentGeomSetSelectionState->AddDialogAgent(_pDialogAgentForSourceSurface);
	VentGeomSetSelectionState->AddDialogAgent(_pDialogAgentForVentGeomSet);
	//---------------------Adding agents to States ENDS----------------------------------//


	//-----------------Agents and Transition STARTS-----------------------------------------// 
	AddTransition(initialState, initialState, IsOutputSetCondition(_pPathElementAgentForSurface), Action((ActionMethod)&MRFBackProfileCmd::OnSourceSurfaceSelected));
	AddTransition(VentGeomSetSelectionState, VentGeomSetSelectionState, IsOutputSetCondition(_pPathElementAgentForVentGeomSet), Action((ActionMethod)&MRFBackProfileCmd::OnVentGeomSetSelected));
	
	AddTransition(initialState, initialState, IsOutputSetCondition(_pDialogAgentForSourceSurface),
		Action((ActionMethod)&MRFBackProfileCmd::OnSelectorListSelected, NULL, NULL, PreDefSelectorListSourceSurf));
	AddTransition(VentGeomSetSelectionState, VentGeomSetSelectionState, IsOutputSetCondition(_pDialogAgentForVentGeomSet),
		Action((ActionMethod)&MRFBackProfileCmd::OnSelectorListSelected, NULL, NULL, PredDefSelectorListVentGeoSet));
	AddTransition(initialState, VentGeomSetSelectionState, IsOutputSetCondition(_pDialogAgentForVentGeomSet), 
		Action((ActionMethod)&MRFBackProfileCmd::OnSelectorListSelected,NULL,NULL, PredDefSelectorListVentGeoSet));
	AddTransition(VentGeomSetSelectionState, initialState, IsOutputSetCondition(_pDialogAgentForSourceSurface),
		Action((ActionMethod)&MRFBackProfileCmd::OnSelectorListSelected,NULL,NULL, PreDefSelectorListSourceSurf));
	//-----------------Agents and Transition ENDS-----------------------------------------// 



}


//-----------------Function to set filter types to CATPathElement Agent to select only surface type STARTS-----------------------------------------// 
CATListOfCATString MRFBackProfileCmd::GetSurfaceSelectorTypes()
{
	CATListOfCATString ListSurfaces;
	ListSurfaces.Append("CATSurface");
	ListSurfaces.Append("CATI3DMUseFunctionalSurface");
	ListSurfaces.Append("CATSweepSurface");
	ListSurfaces.Append("CATRevolutionSurface");
	//ListSurfaces.Append("CATPlane");
	ListSurfaces.Append("CATOffsetSurface");
	ListSurfaces.Append("CATNurbsSurface");
	ListSurfaces.Append("CATIForeignSurface");
	ListSurfaces.Append("CATTorus");
	ListSurfaces.Append("CATSphere");
	ListSurfaces.Append("CATCylinder");
	ListSurfaces.Append("CATCone");
	ListSurfaces.Append("CATElementarySurface");
	ListSurfaces.Append("CATGSMUseItf");
	ListSurfaces.Append("CATIGSMUseRevol");
	ListSurfaces.Append("CATIGSMUseOffset");

	return ListSurfaces;
}
