//-----------------Function to be called whrn PushButton OK clicked in UI STARTS-----------------------------------------------//
void MRFBackProfileCmd::OnOK(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char* data = (char*)(iUsefulData);
	if ("FromPreviewButton" == data && _isPreviewClicked == false)
	{
		_isPreviewClicked = true;

		isOperationsPerformed = this->PerformOperations();

	}
	else if (_isPreviewClicked == false)
	{
		this->PerformOperations();

		RequestDelayedDestruction();
	}
	else if (_isPreviewClicked == true)
	{
		RequestDelayedDestruction();
	}

}
