//-----------------Function to add Contextual menu item to clear existing selected reference surface or VentGeomSet STARTS-----------------------------------------------//
void MRFBackProfileCmd::OnContextMenuSelected(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATString SelectorListIdentifier = (char*)iUsefulData;
	const char* dataToSend = SelectorListIdentifier.ConvertToChar();
	CATDlgContextualMenu * pCtxMenuRefSurface = NULL;
	if (SelectorListIdentifier == PreDefSelectorListSourceSurf)
		pCtxMenuRefSurface = _pMRFBackProfileDlg->GetCustomContextualMenuOfSelectorListSourceSurface();
	else if (SelectorListIdentifier == PredDefSelectorListVentGeoSet)
		pCtxMenuRefSurface = _pMRFBackProfileDlg->GetCustomContextualMenuOfSelectorListVentGeomSet();
	

	if (NULL != pCtxMenuRefSurface)
	{
		CATDlgPushItem * pBtnClrSelSurface = new CATDlgPushItem(pCtxMenuRefSurface, CATString("Clear Selection"));
		if (NULL != pBtnClrSelSurface)
		{
			CATUnicodeString  strClearSelection = "Clear Selection";
			pBtnClrSelSurface->SetTitle(strClearSelection);
			pBtnClrSelSurface->SetIconName("I_ClearSelection1");
			
			if (SelectorListIdentifier == PreDefSelectorListSourceSurf)
				AddAnalyseNotificationCB(pBtnClrSelSurface, pBtnClrSelSurface->GetMenuIActivateNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnCtxMenuClearSelectorList, PreDefSelectorListSourceSurf);
			else if (SelectorListIdentifier == PredDefSelectorListVentGeoSet)
				AddAnalyseNotificationCB(pBtnClrSelSurface, pBtnClrSelSurface->GetMenuIActivateNotification(), (CATCommandMethod)& MRFBackProfileCmd::OnCtxMenuClearSelectorList, PredDefSelectorListVentGeoSet);

		}
	}


}
//-----------------Function to add Contextual menu item to clear existing selected reference surface or VentGeomSet ENDS-----------------------------------------------//

//-----------------Function to clear existing selected reference surface or VentGeom Set when "Clear List" push item selected from contextual menu STARTS--------------//
void MRFBackProfileCmd::OnCtxMenuClearSelectorList(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;

	CATString strAction(pstrAction);

	CATDlgSelectorList* pSelectorListSourceSurface = NULL;


		if (pstrAction == PreDefSelectorListSourceSurf)
		{
			if (NULL != _pHSO && NULL != _pPathElementForSourceSurface && 0 != _pHSO->IsMember(_pPathElementForSourceSurface))
			{
				_pHSO->RemoveElement(_pPathElementForSourceSurface);
			}

			_pPathElementForSourceSurface = NULL;

			pSelectorListSourceSurface = _pMRFBackProfileDlg->GetSelectorListSourceSurf();
		}
		else if (pstrAction == PredDefSelectorListVentGeoSet)
		{
			if (NULL != _pHSO && NULL != _pPathElementForVentGeomSet && 0 != _pHSO->IsMember(_pPathElementForVentGeomSet))
			{
				_pHSO->RemoveElement(_pPathElementForVentGeomSet);
			}

			_pPathElementForVentGeomSet = NULL;

			pSelectorListSourceSurface = _pMRFBackProfileDlg->GetSelectorListVentGeomSet();
		}

		if (pSelectorListSourceSurface)
		{
			ClearAllSelections();
			pSelectorListSourceSurface->ClearSelect();
			pSelectorListSourceSurface->ClearLine();
			pSelectorListSourceSurface->SetLine("No Selection");
			_pMRFBackProfileDlg->SetFocusOnSelectorList(pSelectorListSourceSurface);
			_isSourceSurfaceSelected = false;

			this->EnablePushButtonInstantiate();

		}

}
//-----------------Function to clear existing selected reference surface or VentGeom Set when "Clear List" push item selected from contextual menu ENDS--------------//

