//-----------------------Function to Set focus on user clicked selector list and activates respective dailog agent STARTS-----------//
CATBoolean MRFBackProfileCmd::OnSelectorListSelected(void* iUsefulData)
{
	CATString selectorListType = (char*)iUsefulData;
	if (selectorListType == PreDefSelectorListSourceSurf)
	{
		if (NULL != _pHSO)
		{
			if (0 == _pHSO->IsMember(_pPathElementForSourceSurface))
			{
				_pHSO->Empty();
				_pHSO->AddElement(_pPathElementForSourceSurface);
			}
		}

		CATUnicodeString strString = SelctorListDefVal;
		if (!!_pMRFBackProfileDlg)
		{
			_pMRFBackProfileDlg->SetStatusBarText(strString);
			ClearAllSelections();

			CATDlgSelectorList* pSingleEdgeRefEdgeSelector = NULL;
			pSingleEdgeRefEdgeSelector = _pMRFBackProfileDlg->GetSelectorListSourceSurf();
			if (NULL != pSingleEdgeRefEdgeSelector)
			{
				_pMRFBackProfileDlg->SetFocusOnSelectorList(pSingleEdgeRefEdgeSelector);

			}
		}
		if (!!_pDialogAgentForSourceSurface)
			_pDialogAgentForSourceSurface->InitializeAcquisition();

	}
	else if (selectorListType == PredDefSelectorListVentGeoSet)
	{
		if (NULL != _pHSO)
		{
			if (0 == _pHSO->IsMember(_pPathElementForVentGeomSet))
			{
				_pHSO->Empty();
				_pHSO->AddElement(_pPathElementForVentGeomSet);
			}
		}

		CATUnicodeString strString = SelctorListDefVal;
		if (!!_pMRFBackProfileDlg)
		{
			_pMRFBackProfileDlg->SetStatusBarText(strString);
			ClearAllSelections();

			CATDlgSelectorList* pSelectorListVentGeomSet = NULL;
			pSelectorListVentGeomSet = _pMRFBackProfileDlg->GetSelectorListVentGeomSet();
			if (NULL != pSelectorListVentGeomSet)
			{
				_pMRFBackProfileDlg->SetFocusOnSelectorList(pSelectorListVentGeomSet);

			}
		}
		if (!!_pDialogAgentForVentGeomSet)
			_pDialogAgentForVentGeomSet->InitializeAcquisition();

	}

	return true;
}
//-----------------------Function to Set focus on user clicked selector list and activates respective dailog agent ENDS-----------//

//-----------------------Function to retrieve source surface or tyre surface and store it in a global variable when surface is selected in UI STARTS-----------//
CATBoolean MRFBackProfileCmd::OnSourceSurfaceSelected(void* data)
{
	CATUnicodeString surfaceAliasName;
	cout << "Surface Got Selected\n";
	_pPathElementForSourceSurface = _pPathElementAgentForSurface->GetValue();

	if (_pPathElementForSourceSurface)
	{
		// Add current selection to HSO if not added yet
		if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForSourceSurface))
		{
			_pHSO->Empty();
			_pHSO->AddElement(_pPathElementForSourceSurface);
		}

		CATBaseUnknown* pSelectedSurface = _pPathElementForSourceSurface->CurrentElement(); // No need to release the returned object
		if (pSelectedSurface)
		{
			CATBoolean isSameCurve = CATFalse;
			if (_spSourceSurface == NULL_var)
				_spSourceSurface = pSelectedSurface;
			else if (_spSourceSurface != NULL_var && !_spSourceSurface->IsEqual(pSelectedSurface))
			{
				_spSourceSurface->Release();
				_spSourceSurface = NULL;
				_spSourceSurface = pSelectedSurface;


			}
			else
				isSameCurve = CATTrue;

			//CATIAlias_var pAliasON3DCurve(pSelectedCurve);
			CATIAlias_var pAliasON3DCurve(_spSourceSurface);
			if (!!pAliasON3DCurve) {
				surfaceAliasName = pAliasON3DCurve->GetAlias();
				cout << surfaceAliasName << endl;
			}
			if(pOnMRFBackProfileOperations)
				pOnMRFBackProfileOperations->GetGSMUseFactoryFromFeature(_spSourceSurface);

		}
	}

	_pMRFBackProfileDlg->SetSelectorListSourceSurf(surfaceAliasName);
	_pPathElementAgentForSurface->InitializeAcquisition();

	_isSourceSurfaceSelected = true;
	
	this->EnablePushButtonInstantiate();

	return true;
}
//-----------------------Function to retrieve source surface or tyre surface and store it in a global variable when surface is selected in UI ENDS-----------//

//-----------------------Function to retrieve vent geom set and store it in a global variable when vent geom set is selected in UI STARTS-----------//
CATBoolean MRFBackProfileCmd::OnVentGeomSetSelected(void* data)
{
	CATUnicodeString surfaceAliasName;
	cout << "Surface Got Selected\n";
	_pPathElementForVentGeomSet = _pPathElementAgentForVentGeomSet->GetValue();

	if (_pPathElementForVentGeomSet)
	{
		// Add current selection to HSO if not added yet
		if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForVentGeomSet))
		{
			_pHSO->Empty();
			_pHSO->AddElement(_pPathElementForVentGeomSet);
		}

		CATBaseUnknown* pSelectedSurface = _pPathElementForVentGeomSet->CurrentElement(); // No need to release the returned object
		if (pSelectedSurface)
		{
			CATBoolean isSameCurve = CATFalse;
			if (_spVentGeomSet == NULL_var)
				_spVentGeomSet = pSelectedSurface;
			else if (_spVentGeomSet != NULL_var && !_spVentGeomSet->IsEqual(pSelectedSurface))
			{
				_spVentGeomSet->Release();
				_spVentGeomSet = NULL;
				_spVentGeomSet = pSelectedSurface;


			}
			else
				isSameCurve = CATTrue;

			//CATIAlias_var pAliasON3DCurve(pSelectedCurve);
			CATIAlias_var pAliasON3DCurve(_spVentGeomSet);
			if (!!pAliasON3DCurve) {
				surfaceAliasName = pAliasON3DCurve->GetAlias();
				cout << surfaceAliasName << endl;
			}
		}

		//-------------------The Following functions to be called when user Click OK-------To Be Changed after Testing----STARTS--------------------------/
		if(pOnMRFBackProfileOperations)
		pOnMRFBackProfileOperations->GetGSMUseFactoryFromFeature(_spVentGeomSet);
		this->GetListOfVentsUnderSelectedVentGeomSet(_spVentGeomSet); //Retriev 2DVents and 3DVents under a selected GeomSet
		
		//-------------------The Following functions to be called when user Click OK-------To Be Changed after Testing----ENDS--------------------------/

	}

	_pMRFBackProfileDlg->SetSelectorListVentGeomSet(surfaceAliasName);
	_pPathElementAgentForVentGeomSet->InitializeAcquisition();

	return true;
}
