//-----------------------Function to read BAckprofile count from NLS file and Set the name of the backprofile to combo box STARTS-----------//
void MRFBackProfileCmd::ReadProfileCountFromNLSFile(CATDlgCombo* pOnComboBackProfile)
{
	CATUnicodeString  strOnProfileCount = CATMsgCatalog::BuildMessage("MRFBackProfileCmd", "MRFBackProfileCmd.ProfileCount"); 
	int profileCount = 0; 
	strOnProfileCount.ConvertToNum(&profileCount);

	if (profileCount >= 1)
	{
		//CATDlgCombo* pOnComboBackProfile = _pMRFBackProfileDlg->GetComboBoxBackProfile();
		if (pOnComboBackProfile)
		{
			_listOfFeatToBeCopiedFromAllProfile.RemoveAll();

			for (int i = 1; i <= profileCount; i++)
			{
				CATUnicodeString strListProf = PreDefProfileName;
				CATUnicodeString nameToAppend;
				nameToAppend.BuildFromNum(i);
				strListProf.Append(nameToAppend);
				
				CATUnicodeString profName = strListProf;
				profName.Append(".Name");
				CATUnicodeString  constName = CATMsgCatalog::BuildMessage("MRFBackProfileCmd", profName.ConvertToChar());
				
				CATUnicodeString revision = strListProf;
				revision.Append(".Rev");
				constName.Append("." + CATMsgCatalog::BuildMessage("MRFBackProfileCmd", revision.ConvertToChar()));
				
				pOnComboBackProfile->SetLine(constName);

				CATUnicodeString featToBeCopiedName = strListProf;
				featToBeCopiedName.Append(".FeaturesToBeCopied");
				CATUnicodeString  featuresName = CATMsgCatalog::BuildMessage("MRFBackProfileCmd", featToBeCopiedName.ConvertToChar());
				_listOfFeatToBeCopiedFromAllProfile.Append(featuresName);

				CATUnicodeString parametersToBeCopied = strListProf;
				parametersToBeCopied.Append(".Parameter");
				CATUnicodeString  parmName = CATMsgCatalog::BuildMessage("MRFBackProfileCmd", parametersToBeCopied.ConvertToChar());
				_listOfParmsToBeCopiedFromAllProfile.Append(parmName);
					
			}

			CATUnicodeString strPartName;
			pOnComboBackProfile->GetLine(strPartName, 0);
			this->RetrieveActiveProfileInfo(0, strPartName);

		}

	}
}
